  function isTotalEpisodeCountMatch(title, match) {
    const index = typeof match.index === "number" ? match.index : -1;
    if (index < 0) return false;
    return /全\s*$/.test(String(title || "").slice(0, index));
  }

  function isEpisodeRangeMatch(match) {
    return /[0-9]+(?:\.[0-9]+)?\s*[-~～至到]\s*[0-9]+(?:\.[0-9]+)?/.test(String(match && match[0] || ""));
  }

  function hasEpisodeRangeMarker(text) {
    const title = String(text || "");
    return /第\s*[0-9]+(?:\.[0-9]+)?\s*[-~～至到]\s*[0-9]+(?:\.[0-9]+)?\s*[话話集]/i.test(title)
      || /第\s*[0-9]+(?:\.[0-9]+)?\s+[0-9]+(?:\.[0-9]+)?\s*[话話集]/i.test(title)
      || /(?:^|[\s#\[])[0-9]+(?:\.[0-9]+)?\s*[-~～至到]\s*[0-9]+(?:\.[0-9]+)?\s*(?:话|話|集|]|$)/i.test(title);
  }

  function detectCurrentEpisodeNo(rawTitle) {
    const titleEpisodeNo = detectEpisodeNo(rawTitle);
    if (titleEpisodeNo) return titleEpisodeNo;
    if (hasEpisodeRangeMarker(rawTitle)) return detectEpisodeNo(getActiveEpisodeText()) || getCurrentVideoPartEpisodeNo();
    if (isNonMainEpisodeTitle(rawTitle)) return null;
    return detectEpisodeNo(getActiveEpisodeText()) || getCurrentVideoPartEpisodeNo();
  }

  function scheduleEpisodeContextRefresh() {
    const seq = ++episodeContextRefreshSeq;
    [250, 800, 1600, 3000, 5000].forEach((delay) => {
      window.setTimeout(() => refreshEpisodeContextIfChanged(seq), delay);
    });
    observeEpisodeContextUntilSettled(seq);
  }

  function observeEpisodeContextUntilSettled(seq) {
    if (!isOfficialBangumiPage()) return;
    if (episodeContextObserver) episodeContextObserver.disconnect();
    if (episodeContextObserverStopTimer) window.clearTimeout(episodeContextObserverStopTimer);
    episodeContextObserver = new MutationObserver(() => {
      if (seq !== episodeContextRefreshSeq || episodeContextRefreshTimer) return;
      episodeContextRefreshTimer = window.setTimeout(() => {
        episodeContextRefreshTimer = 0;
        refreshEpisodeContextIfChanged(seq);
      }, 160);
    });
    episodeContextObserver.observe(document.documentElement, { childList: true, subtree: true, characterData: true });
    episodeContextObserverStopTimer = window.setTimeout(() => {
      if (seq === episodeContextRefreshSeq && episodeContextObserver) {
        episodeContextObserver.disconnect();
        episodeContextObserver = null;
      }
    }, 8000);
  }

  function refreshEpisodeContextIfChanged(seq) {
    if (seq !== episodeContextRefreshSeq) return;
    const rawTitle = getPageTitle();
    if (isCurrentVideoAutoProgressDisabled()) {
      if (state.currentEpisodeNo !== null) {
        state.rawTitle = rawTitle;
        state.currentEpisodeNo = null;
        render();
      }
      return;
    }
    if (getLongVideoEpisodeModeDecision() === true || (state.longVideoEpisodeGuess && state.longVideoEpisodeGuess.active)) return;
    const nextEpisodeNo = detectCurrentEpisodeNo(rawTitle);
    const safeNextEpisodeNo = Number(nextEpisodeNo);
    if (!Number.isFinite(safeNextEpisodeNo) || safeNextEpisodeNo <= 0) return;
    if (Number(state.currentEpisodeNo) === safeNextEpisodeNo) return;
    state.rawTitle = rawTitle;
    state.currentEpisodeNo = safeNextEpisodeNo;
    render();
  }

  function parseLongVideoPartTitle(value) {
    const text = String(value || "").replace(/\s+/g, " ").trim();
    if (!text) return null;
    const rangeMatch = text.match(/(?:^|[^A-Z0-9])(?:S|SEASON)\s*0*(\d{1,2})\s*(?:E(?:P)?\.?\s*)?0*(\d{1,3})(?:\s*[-~～–—至到]\s*(?:E(?:P)?\.?\s*)?0*(\d{1,3}))?/i);
    if (rangeMatch) {
      const seasonNo = Number(rangeMatch[1]);
      const episodeStart = Number(rangeMatch[2]);
      const episodeEnd = Number(rangeMatch[3] || rangeMatch[2]);
      if (seasonNo > 0 && episodeStart > 0 && episodeEnd >= episodeStart) {
        return { seasonNo, episodeStart, episodeEnd, rangeLabel: `S${seasonNo} ${episodeStart}-${episodeEnd}` };
      }
    }
    const seasonMatch = text.match(/(?:^|[^A-Z0-9])(?:S|SEASON)\s*0*(\d{1,2})(?:\b|\s)/i);
    const seasonNo = seasonMatch ? Number(seasonMatch[1]) : 0;
    return seasonNo > 0 ? { seasonNo, episodeStart: null, episodeEnd: null, rangeLabel: `S${seasonNo}` } : null;
  }

  function getVideoPartListNodes() {
    if (!document || typeof document.querySelectorAll !== "function") return [];
    const activeSelectors = [
      [".multi-p .page-list .page-item.active, .multi-p .page-list .page-item.on", ".page-list"],
      [".video-pod__list .video-pod__item.active, .video-pod__list [class*='base-item'].active", ".video-pod__list"],
      [".bpx-player-ctrl-eplist-episodes-content > .bpx-state-multi-active-item", ".bpx-player-ctrl-eplist-episodes-content"],
    ];
    if (typeof document.querySelector === "function") {
      for (const [selector, containerSelector] of activeSelectors) {
        const active = document.querySelector(selector);
        if (!active) continue;
        const container = typeof active.closest === "function" ? active.closest(containerSelector) : active.parentElement;
        const nodes = container && container.children ? Array.from(container.children) : [];
        if (nodes.length > 1) return nodes;
      }
    }
    const fallbackSelectors = [
      ".multi-p .page-list .page-item",
      ".video-pod__list .video-pod__item",
      ".bpx-player-ctrl-eplist-episodes-content > .bpx-player-ctrl-eplist-multi-menu-item",
    ];
    for (const selector of fallbackSelectors) {
      const nodes = Array.from(document.querySelectorAll(selector));
      if (nodes.length > 1 && nodes.length <= 50) return nodes;
    }
    return [];
  }

  function isActiveVideoPartNode(node) {
    const className = String(node && node.className || "");
    return /(?:^|\s)(?:active|on|bpx-state-multi-active-item)(?:\s|$)/i.test(className);
  }

  function getVideoPartNodeTitle(node) {
    if (!node) return "";
    const candidates = [node.getAttribute && node.getAttribute("title"), node.getAttribute && node.getAttribute("aria-label")];
    if (typeof node.querySelectorAll === "function") {
      Array.from(node.querySelectorAll("[title], [class*='title'], [class*='Title']")).slice(0, 6).forEach((child) => {
        candidates.push(child.getAttribute("title"), child.getAttribute("aria-label"), child.textContent);
      });
    }
    candidates.push(node.textContent);
    return candidates
      .map((text) => stripTrailingDurationText(String(text || "").replace(/\s+/g, " ").trim()))
      .find(Boolean) || "";
  }

  function getCurrentVideoPartContext() {
    const bvid = String(getBvIdFromUrl() || "").toUpperCase();
    if (!bvid) return null;
    const nodes = getVideoPartListNodes();
    const activeNode = nodes.find(isActiveVideoPartNode) || null;
    const activeIndex = activeNode ? nodes.indexOf(activeNode) : -1;
    const urlPartNo = getCurrentPartNoFromUrl();
    const partNo = urlPartNo || (activeIndex >= 0 ? activeIndex + 1 : 1);
    const selectedNode = activeNode || (partNo > 0 && partNo <= nodes.length ? nodes[partNo - 1] : null);
    const title = getVideoPartNodeTitle(selectedNode);
    const parsed = parseLongVideoPartTitle(title) || {};
    return {
      bvid,
      partNo,
      partCount: Math.max(nodes.length, urlPartNo || 1),
      title,
      seasonNo: Number(parsed.seasonNo) || null,
      episodeStart: Number(parsed.episodeStart) || null,
      episodeEnd: Number(parsed.episodeEnd) || null,
      rangeLabel: parsed.rangeLabel || "",
    };
  }

  function getCurrentLongVideoPartBindingKey() {
    const part = getCurrentVideoPartContext();
    if (getLongVideoEpisodeModeDecision() !== true || !part || part.partCount <= 1 || !part.seasonNo) return "";
    return `bili:${part.bvid}:p${part.partNo}`;
  }

  function selectLongVideoEpisodeSegment(episodes, part) {
    const allEpisodes = Array.isArray(episodes) ? episodes : [];
    const start = Number(part && part.episodeStart);
    const end = Number(part && part.episodeEnd);
    const base = {
      episodes: allEpisodes,
      firstEpisodeNo: 1,
      part: part || null,
      rangeApplied: false,
      rangeFallback: false,
      rangeLabel: String(part && part.rangeLabel || ""),
    };
    if (!Number.isInteger(start) || !Number.isInteger(end) || start <= 0 || end < start) return base;
    if (start > allEpisodes.length || end > allEpisodes.length) {
      return { ...base, rangeFallback: true };
    }
    const selected = allEpisodes.slice(start - 1, end);
    return selected.length
      ? { ...base, episodes: selected, firstEpisodeNo: start, rangeApplied: true }
      : { ...base, rangeFallback: true };
  }

  function getLongVideoEpisodeSegment(episodes = getNormalEpisodes()) {
    return selectLongVideoEpisodeSegment(episodes, getCurrentVideoPartContext());
  }

  function getLongVideoPartCacheKey() {
    const part = getCurrentVideoPartContext();
    return part ? `${part.bvid}:p${part.partNo}:${part.title}` : "single";
  }

  function getLongVideoOwnerKey() {
    const owner = getLongVideoOwnerInfo();
    const mid = String(owner && (owner.mid || owner.uid) || "").trim();
    return /^\d+$/.test(mid) ? `mid:${mid}` : "";
  }

  function getLongVideoOwnerLabel() {
    const owner = getLongVideoOwnerInfo();
    const mid = String(owner && (owner.mid || owner.uid) || "").trim();
    const name = String(owner && owner.name || "").trim();
    return name ? `${name}${mid ? `（UID ${mid}）` : ""}` : (mid ? `UID ${mid}` : "当前 UP");
  }

  function getLongVideoOwnerInfo() {
    const domOwner = getPrimaryDomOwnerInfo();
    if (domOwner && (domOwner.mid || domOwner.uid)) return domOwner;
    const initial = window.__INITIAL_STATE__ || {};
    const videoData = initial.videoData || initial.videoInfo || {};
    const currentBvidMatch = location.pathname.match(/\/video\/(BV[\w]+)/i);
    const currentBvid = currentBvidMatch ? currentBvidMatch[1].toUpperCase() : "";
    const initialBvid = String(videoData.bvid || initial.bvid || "").toUpperCase();
    if (currentBvid && initialBvid && currentBvid !== initialBvid) return {};
    return getInitialOwnerInfo(initial, videoData);
  }

  function getLongVideoOffsetSeconds(ownerKey = getLongVideoOwnerKey()) {
    const stored = ownerKey && state.longVideoEpisodeOffsets && state.longVideoEpisodeOffsets[ownerKey];
    return stored === undefined
      ? DEFAULT_LONG_VIDEO_EPISODE_OFFSET_SECONDS
      : normalizeLongVideoOffsetSeconds(stored);
  }

  function getCurrentVideoProgressKey() {
    if (isOfficialBangumiPage()) {
      const match = location.pathname.match(/\/bangumi\/play\/ep(\d+)/i);
      return match ? `bangumi:ep${match[1]}` : "";
    }
    return getLongVideoDecisionKey() || "";
  }

  function isCurrentVideoAutoProgressDisabled() {
    const map = state.disabledAutoProgressVideos;
    if (!map || typeof map !== "object") return false;
    const key = getCurrentVideoProgressKey();
    if (key && Object.prototype.hasOwnProperty.call(map, key)) return map[key] === true;
    const legacyKey = getLongVideoLegacyDecisionKey();
    if (legacyKey && legacyKey !== key && Object.prototype.hasOwnProperty.call(map, legacyKey)) return map[legacyKey] === true;
    return false;
  }

  function getLongVideoVideoOffsetSeconds() {
    if (!state.longVideoEpisodeVideoOffsets || typeof state.longVideoEpisodeVideoOffsets !== "object") return null;
    const key = getLongVideoDecisionKey();
    if (key && Object.prototype.hasOwnProperty.call(state.longVideoEpisodeVideoOffsets, key)) {
      return { key, seconds: normalizeLongVideoOffsetSeconds(state.longVideoEpisodeVideoOffsets[key]) };
    }
    const legacyKey = getLongVideoLegacyDecisionKey();
    if (legacyKey && legacyKey !== key && Object.prototype.hasOwnProperty.call(state.longVideoEpisodeVideoOffsets, legacyKey)) {
      return { key: legacyKey, seconds: normalizeLongVideoOffsetSeconds(state.longVideoEpisodeVideoOffsets[legacyKey]) };
    }
    return null;
  }

  function getEffectiveLongVideoOffsetSeconds(ownerKey = getLongVideoOwnerKey()) {
    const videoOffset = getLongVideoVideoOffsetSeconds();
    if (videoOffset) return videoOffset.seconds;
    return getLongVideoOffsetSeconds(ownerKey);
  }

  async function setLongVideoVideoOffsetSeconds(seconds) {
    const key = getCurrentVideoProgressKey() || getLongVideoDecisionKey();
    if (!key) return false;
    const normalized = normalizeLongVideoOffsetSeconds(seconds);
    state.longVideoEpisodeVideoOffsets = {
      ...(state.longVideoEpisodeVideoOffsets && typeof state.longVideoEpisodeVideoOffsets === "object" ? state.longVideoEpisodeVideoOffsets : {}),
      [key]: normalized,
    };
    await writeJsonValueAsync(STORAGE.longVideoEpisodeVideoOffsets, state.longVideoEpisodeVideoOffsets);
    state.longVideoDetectionCache = null;
    resetAutoWatchObservationState();
    return true;
  }

  async function clearLongVideoVideoOffset() {
    const key = getCurrentVideoProgressKey() || getLongVideoDecisionKey();
    if (!key || !state.longVideoEpisodeVideoOffsets || typeof state.longVideoEpisodeVideoOffsets !== "object") return false;
    const legacyKey = getLongVideoLegacyDecisionKey();
    const next = { ...state.longVideoEpisodeVideoOffsets };
    let changed = false;
    if (Object.prototype.hasOwnProperty.call(next, key)) { delete next[key]; changed = true; }
    if (legacyKey && legacyKey !== key && Object.prototype.hasOwnProperty.call(next, legacyKey)) { delete next[legacyKey]; changed = true; }
    if (!changed) return false;
    state.longVideoEpisodeVideoOffsets = next;
    await writeJsonValueAsync(STORAGE.longVideoEpisodeVideoOffsets, state.longVideoEpisodeVideoOffsets);
    state.longVideoDetectionCache = null;
    resetAutoWatchObservationState();
    return true;
  }

  async function captureLongVideoVideoOffsetFromPlayer() {
    const video = getActiveVideoElement();
    const currentTime = Number(video && video.currentTime);
    if (!video || !Number.isFinite(currentTime) || currentTime < 0) {
      state.error = "找不到播放器进度，请在视频播放页再试。";
      state.message = "";
      render();
      return;
    }
    const ok = await setLongVideoVideoOffsetSeconds(currentTime);
    if (!ok) {
      state.error = "当前页面无法保存本视频首集开始时间。";
      state.message = "";
      render();
      return;
    }
    state.error = "";
    state.message = `已把本视频首集开始时间设为 ${formatTimecode(currentTime)}。`;
    if (!isCurrentVideoAutoProgressDisabled()) {
      refreshLongVideoEpisodeGuess(video);
    }
    remountSettingsDialog();
    render();
  }

  async function setCurrentVideoAutoProgressDisabled(disabled) {
    const key = getCurrentVideoProgressKey();
    if (!key) return;
    const next = {
      ...(state.disabledAutoProgressVideos && typeof state.disabledAutoProgressVideos === "object" ? state.disabledAutoProgressVideos : {}),
    };
    if (disabled) next[key] = true;
    else {
      delete next[key];
      const legacyKey = getLongVideoLegacyDecisionKey();
      if (legacyKey && legacyKey !== key) delete next[legacyKey];
    }
    state.disabledAutoProgressVideos = next;
    await writeJsonValueAsync(STORAGE.disabledAutoProgressVideos, state.disabledAutoProgressVideos);
    state.longVideoDetectionCache = null;
    resetAutoWatchObservationState();
    if (disabled) {
      if (state.longVideoEpisodeGuess) resetLongVideoEpisodeGuess(false);
      state.currentEpisodeNo = null;
    } else {
      state.currentEpisodeNo = detectCurrentEpisodeNo(state.rawTitle || getPageTitle());
      const video = getActiveVideoElement();
      if (video) refreshLongVideoEpisodeGuess(video);
    }
    render();
  }

  function getLongVideoSettingsContext() {
    const ownerKey = getLongVideoOwnerKey();
    const detection = getLongVideoDetection(getActiveVideoElement());
    const videoOffset = getLongVideoVideoOffsetSeconds();
    return {
      ownerKey,
      ownerLabel: getLongVideoOwnerLabel(),
      offsetSeconds: getLongVideoOffsetSeconds(ownerKey),
      videoKey: getCurrentVideoProgressKey() || getLongVideoDecisionKey() || "",
      videoOffsetSeconds: videoOffset ? videoOffset.seconds : null,
      statusText: ` 当前检测：${detection.reason}`,
    };
  }

  function getLongVideoLegacyDecisionKey() {
    const match = location.pathname.match(/\/video\/(BV[\w]+)/i);
    return match ? `bvid:${match[1].toUpperCase()}` : "";
  }

  function getLongVideoDecisionKey() {
    const legacyKey = getLongVideoLegacyDecisionKey();
    const part = getCurrentVideoPartContext();
    return legacyKey && part && part.partCount > 1 && part.seasonNo
      ? `${legacyKey}:p${part.partNo}`
      : legacyKey;
  }

  function getLongVideoEpisodeModeDecision() {
    const key = getLongVideoDecisionKey();
    if (!key || !state.longVideoEpisodeModes) return null;
    if (Object.prototype.hasOwnProperty.call(state.longVideoEpisodeModes, key)) return state.longVideoEpisodeModes[key] === true;
    const legacyKey = getLongVideoLegacyDecisionKey();
    if (legacyKey && legacyKey !== key && Object.prototype.hasOwnProperty.call(state.longVideoEpisodeModes, legacyKey)) {
      return state.longVideoEpisodeModes[legacyKey] === true;
    }
    return null;
  }

  function getLongVideoDurationSeconds(video) {
    const direct = Number(video && video.duration);
    if (Number.isFinite(direct) && direct > 0) return direct;
    const initial = window.__INITIAL_STATE__ || {};
    const videoData = initial.videoData || initial.videoInfo || {};
    const currentBvidMatch = location.pathname.match(/\/video\/(BV[\w]+)/i);
    const currentBvid = currentBvidMatch ? currentBvidMatch[1].toUpperCase() : "";
    const initialBvid = String(videoData.bvid || initial.bvid || "").toUpperCase();
    const fallback = Number(videoData.duration || initial.duration);
    return (!currentBvid || !initialBvid || currentBvid === initialBvid) && Number.isFinite(fallback) && fallback > 0 ? fallback : 0;
  }

  function shouldOfferLongVideoBindingPrompt(video) {
    return getLongVideoBindReadiness(video).action === "prompt";
  }

  function getLongVideoBindReadiness(video) {
    if (isOfficialBangumiPage() || !/\/video\//i.test(location.pathname)) {
      return { action: "bind", reason: "not_applicable" };
    }
    if (getLongVideoEpisodeModeDecision() !== null) {
      return { action: "bind", reason: "decision_known" };
    }
    const duration = getLongVideoDurationSeconds(video);
    if (!Number.isFinite(duration) || duration <= 0) {
      return {
        action: "wait",
        reason: "duration_unknown",
        waitingFor: "duration",
        statusText: "正在读取视频时长…",
        durationSeconds: 0,
      };
    }
    if (duration > LONG_VIDEO_MIN_DURATION_SECONDS) {
      if (state.longVideoEpisodeGuessEnabled) {
        return {
          action: "auto",
          reason: "auto_identify",
          durationSeconds: duration,
        };
      }
      return {
        action: "prompt",
        reason: "long_duration",
        durationSeconds: duration,
      };
    }
    return {
      action: "bind",
      reason: "short_duration",
      durationSeconds: duration,
    };
  }

  async function setLongVideoEpisodeModeDecision(enabled) {
    const key = getLongVideoDecisionKey();
    if (!key) return;
    state.longVideoEpisodeModes = { ...state.longVideoEpisodeModes, [key]: Boolean(enabled) };
    await writeJsonValueAsync(STORAGE.longVideoEpisodeModes, state.longVideoEpisodeModes);
    state.longVideoDetectionCache = null;
    resetAutoWatchObservationState();
  }

  async function clearLongVideoEpisodeModeDecision() {
    const key = getLongVideoDecisionKey();
    const legacyKey = getLongVideoLegacyDecisionKey();
    if (!key) return;
    const next = { ...state.longVideoEpisodeModes };
    delete next[key];
    if (legacyKey) {
      delete next[legacyKey];
      const partPrefix = `${legacyKey}:p`;
      for (const k of Object.keys(next)) {
        if (k.startsWith(partPrefix)) delete next[k];
      }
    }
    state.longVideoEpisodeModes = next;
    await writeJsonValueAsync(STORAGE.longVideoEpisodeModes, state.longVideoEpisodeModes);
    state.longVideoDetectionCache = null;
    resetAutoWatchObservationState();
  }

  function getLongVideoDetection(video) {
    if (isOfficialBangumiPage() || !/\/video\//i.test(location.pathname)) return { active: false, reason: "仅支持普通 B站视频页。" };
    const duration = getLongVideoDurationSeconds(video);
    if (!Number.isFinite(duration) || duration <= 0) return { active: false, reason: "正在等待播放器时长。" };
    if (duration <= LONG_VIDEO_MIN_DURATION_SECONDS) return { active: false, reason: `视频未超过 ${formatTimecode(LONG_VIDEO_MIN_DURATION_SECONDS)}。` };
    const decision = getLongVideoEpisodeModeDecision();
    if (decision === null) return { active: false, reason: "绑定时尚未确认此视频是否包含连续多集正片。" };
    if (!decision) return { active: false, reason: "当前视频已选择按普通视频处理。" };
    const ownerKey = getLongVideoOwnerKey();
    if (!ownerKey) return { active: false, reason: "尚未识别当前 UP 的 UID。" };
    if (!state.subjectId) return { active: false, reason: "当前视频尚未绑定 Bangumi 条目。" };
    const allEpisodes = getNormalEpisodes();
    let segment = getLongVideoEpisodeSegment(allEpisodes);
    let episodes = segment.episodes;
    const minimumEpisodes = segment.rangeApplied ? 1 : 4;
    if (episodes.length < minimumEpisodes) return { active: false, reason: `Bangumi 可用正片章节少于 ${minimumEpisodes} 集。` };
    const startOffset = getEffectiveLongVideoOffsetSeconds(ownerKey);
    let timeline = buildLongVideoEpisodeTimeline(episodes, startOffset, segment.firstEpisodeNo);
    let rangeTimingMismatch = segment.rangeApplied && duration - timeline.endTime > LONG_VIDEO_DISPLAY_OVERFLOW_TOLERANCE_SECONDS;
    if (rangeTimingMismatch && episodes.length < allEpisodes.length) {
      const fallbackTimeline = buildLongVideoEpisodeTimeline(allEpisodes, startOffset, 1);
      if (Math.max(0, fallbackTimeline.endTime - duration) <= LONG_VIDEO_DISPLAY_OVERFLOW_TOLERANCE_SECONDS) {
        segment = { ...segment, episodes: allEpisodes, firstEpisodeNo: 1, rangeApplied: false, rangeFallback: true };
        episodes = allEpisodes;
        timeline = fallbackTimeline;
        rangeTimingMismatch = false;
      }
    }
    const overflowSeconds = Math.max(0, timeline.endTime - duration);
    if (overflowSeconds > LONG_VIDEO_DISPLAY_OVERFLOW_TOLERANCE_SECONDS) {
      return { active: false, reason: "首集起点加全季时长已超过视频总长，请校准首集开始时间。" };
    }
    const autoMarkSafe = !segment.rangeFallback && !rangeTimingMismatch && timeline.safeForAutoMark && overflowSeconds <= LONG_VIDEO_AUTO_MARK_OVERFLOW_TOLERANCE_SECONDS;
    return {
      active: true,
      reason: segment.rangeFallback
        ? `分P标注的 ${segment.rangeLabel || "章节范围"} 与当前 Bangumi 条目或视频时长不吻合，已按整季显示推测且不会自动标记。`
        : rangeTimingMismatch
        ? `分P标注的 ${segment.rangeLabel || "章节范围"} 对应正片时长明显短于视频，仅显示推测且不会自动标记。`
        : autoMarkSafe
        ? "条件已满足，将按分集局部进度推测。"
        : "条件已满足，但分集时长不完整或时间线与视频不完全吻合，仅显示推测，不自动标记。",
      duration,
      timeline,
      autoMarkSafe,
      segment,
      rangeTimingMismatch,
    };
  }

  function buildLongVideoEpisodeTimeline(episodes, offsetSeconds, firstEpisodeNo = 1) {
    const normalized = episodes.map((episode) => getEpisodeDurationSeconds(episode));
    const knownDurations = normalized.filter((value) => Number.isFinite(value) && value > 0);
    const fallbackDuration = knownDurations.length ? median(knownDurations) : DEFAULT_EPISODE_DURATION_SECONDS;
    const startOffset = normalizeLongVideoOffsetSeconds(offsetSeconds);
    let cursor = startOffset;
    const items = episodes.map((episode, index) => {
      const knownDuration = normalized[index];
      const duration = knownDuration || fallbackDuration;
      const item = { episode, localNo: firstEpisodeNo + index, startTime: cursor, endTime: cursor + duration, duration, durationEstimated: !knownDuration };
      cursor = item.endTime;
      return item;
    });
    return {
      items,
      startTime: startOffset,
      endTime: cursor,
      knownDurationCount: knownDurations.length,
      safeForAutoMark: knownDurations.length === episodes.length,
    };
  }

  function getEpisodeDurationSeconds(episode) {
    const parsed = Number(episode && episode.duration_seconds);
    if (Number.isFinite(parsed) && parsed >= 60 && parsed <= 3 * 60 * 60) return Math.round(parsed);
    return parseEpisodeDurationText(episode && episode.duration);
  }

  function parseEpisodeDurationText(value) {
    const text = String(value || "").trim().toLowerCase();
    if (!text) return 0;
    if (/^\d{1,3}:\d{2}(?::\d{2})?$/.test(text)) {
      const parts = text.split(":").map(Number);
      const seconds = parts.length === 3 ? parts[0] * 3600 + parts[1] * 60 + parts[2] : parts[0] * 60 + parts[1];
      return seconds >= 60 && seconds <= 3 * 60 * 60 ? seconds : 0;
    }
    let seconds = 0;
    const hours = text.match(/(\d+(?:\.\d+)?)\s*(?:h|hr|hrs|hour|hours|小时|小時)/);
    const minutes = text.match(/(\d+(?:\.\d+)?)\s*(?:m|min|mins|minute|minutes|分钟|分鐘|分)/);
    const secs = text.match(/(\d+(?:\.\d+)?)\s*(?:s|sec|secs|second|seconds|秒)/);
    if (hours) seconds += Number(hours[1]) * 3600;
    if (minutes) seconds += Number(minutes[1]) * 60;
    if (secs) seconds += Number(secs[1]);
    return Number.isFinite(seconds) && seconds >= 60 && seconds <= 3 * 60 * 60 ? Math.round(seconds) : 0;
  }

  function inferLongVideoEpisode(video, detection) {
    if (!detection || !detection.active || !detection.timeline) return null;
    const currentTime = Number(video && video.currentTime);
    if (!Number.isFinite(currentTime) || currentTime < 0) return null;
    const timeline = detection.timeline;
    if (currentTime < timeline.startTime) {
      return { active: true, stage: "prelude", episode: null, currentTime, ...detection };
    }
    const item = timeline.items.find((entry) => currentTime < entry.endTime);
    if (!item) return { active: true, stage: "outro", episode: null, currentTime, ...detection };
    const episodeElapsed = Math.max(0, currentTime - item.startTime);
    return {
      active: true,
      stage: "episode",
      episode: item.episode,
      episodeNo: item.localNo,
      episodeElapsed,
      episodeDuration: item.duration,
      episodePercent: Math.max(0, Math.min(100, Math.floor((episodeElapsed / item.duration) * 100))),
      currentTime,
      ...detection,
    };
  }

  function getLongVideoDetectionCacheKey(video) {
    const now = Date.now();
    const cheapKey = [
      state.pageKey,
      String(location.search || ""),
      String(state.subjectId || 0),
      String(state.episodes.length),
      String(Math.round(getLongVideoDurationSeconds(video))),
    ].join("|");
    const memo = state.longVideoDetectionKeyMemo;
    if (memo && memo.cheapKey === cheapKey && now - memo.stamp < LONG_VIDEO_DETECTION_KEY_MEMO_MS) {
      return memo.fullKey;
    }
    const fullKey = [
      state.pageKey,
      getLongVideoPartCacheKey(),
      String(state.subjectId || 0),
      String(state.episodes.length),
      String(Math.round(getLongVideoDurationSeconds(video))),
      String(getLongVideoEpisodeModeDecision()),
      String(getEffectiveLongVideoOffsetSeconds()),
    ].join("|");
    state.longVideoDetectionKeyMemo = { cheapKey, fullKey, stamp: now };
    return fullKey;
  }

  function refreshLongVideoEpisodeGuess(video) {
    if (isCurrentVideoAutoProgressDisabled()) {
      if (state.longVideoEpisodeGuess) resetLongVideoEpisodeGuess(true);
      return null;
    }
    const detectionCacheKey = getLongVideoDetectionCacheKey(video);
    const cachedDetection = state.longVideoDetectionCache;
    const detection = cachedDetection && cachedDetection.key === detectionCacheKey
      ? cachedDetection.value
      : getLongVideoDetection(video);
    if (detection.active && (!cachedDetection || cachedDetection.key !== detectionCacheKey)) {
      state.longVideoDetectionCache = { key: detectionCacheKey, value: detection };
    }
    if (!detection.active) {
      if (state.longVideoEpisodeGuess) resetLongVideoEpisodeGuess(true);
      return null;
    }
    const guess = inferLongVideoEpisode(video, detection);
    if (!guess) return null;
    const nextEpisodeNo = guess.episode ? Number(guess.episodeNo) : null;
    const renderKey = `${guess.stage}:${nextEpisodeNo || 0}:${guess.stage === "episode" ? Math.floor(guess.episodePercent / 10) : 0}`;
    const changed = renderKey !== state.longVideoEpisodeRenderKey || Number(state.currentEpisodeNo) !== Number(nextEpisodeNo);
    state.longVideoEpisodeGuess = guess;
    state.longVideoEpisodeRenderKey = renderKey;
    state.currentEpisodeNo = nextEpisodeNo;
    if (changed) render();
    return guess;
  }

  function resetLongVideoEpisodeGuess(shouldRender = false) {
    const hadGuess = Boolean(state.longVideoEpisodeGuess);
    state.longVideoEpisodeGuess = null;
    state.longVideoEpisodeRenderKey = "";
    state.longVideoDetectionCache = null;
    state.longVideoDetectionKeyMemo = null;
    resetAutoWatchObservationState();
    state.currentEpisodeNo = isCurrentVideoAutoProgressDisabled()
      ? null
      : detectCurrentEpisodeNo(state.rawTitle || getPageTitle());
    if (shouldRender && hadGuess) render();
  }

  function renderLongVideoOffsetActions() {
    const videoOffset = getLongVideoVideoOffsetSeconds();
    const canCapture = Boolean(getCurrentVideoProgressKey() || getLongVideoDecisionKey());
    const captureButton = `<button type="button" class="biligumi-button" data-action="capture-long-video-video-offset" ${canCapture ? "" : "disabled"} title="把当前播放进度设为本视频首集起点">取当前进度为首集起点</button>`;
    const meta = videoOffset
      ? `<span class="biligumi-long-video-hint-meta">本视频起点 ${escapeHtml(formatTimecode(videoOffset.seconds))}</span>
         <button type="button" class="biligumi-button" data-action="clear-long-video-video-offset" title="清除本视频专属首集起点">清除</button>`
      : "";
    return `<div class="biligumi-long-video-hint-actions">${captureButton}${meta}</div>`;
  }

  function renderLongVideoEpisodeHint() {
    const guess = state.longVideoEpisodeGuess;
    if (!guess || !guess.active) return "";
    const actions = renderLongVideoOffsetActions();
    let text = "";
    if (guess.stage === "prelude") {
      text = `实验推测：正片尚未开始；当前起点为 ${escapeHtml(formatTimecode(guess.timeline.startTime))}。`;
    } else if (guess.stage === "outro") {
      text = "实验推测：全季正片已播放完，当前可能是结尾防审核片段。";
    } else {
      const name = String(guess.episode && (guess.episode.name_cn || guess.episode.name) || "").trim();
      const segment = guess.segment || {};
      const partNote = segment.rangeApplied
        ? ` · 分P ${escapeHtml(segment.rangeLabel || segment.part?.title || "")}`
        : (segment.rangeFallback ? ` · ${escapeHtml(segment.rangeLabel || "分P范围")} 无法与条目对应，已按整季估算` : "");
      const safety = guess.autoMarkSafe ? "" : " · 仅显示推测，不会自动标记";
      text = `实验推测：第 ${guess.episodeNo} 集 · 本集约 ${guess.episodePercent}%${name ? ` · ${escapeHtml(name)}` : ""}${partNote}${safety}`;
    }
    return `<div class="biligumi-long-video-hint"><div class="biligumi-long-video-hint-text">${text}</div>${actions}</div>`;
  }

  function parseTimecode(value) {
    const text = String(value || "").trim();
    if (!text) return null;
    if (/^\d+(?:\.\d+)?\s*(?:分钟|分鐘|分|min|mins|minute|minutes)$/i.test(text)) {
      return normalizeLongVideoOffsetSeconds(Number.parseFloat(text) * 60);
    }
    if (/^\d+(?:\.\d+)?$/.test(text)) return normalizeLongVideoOffsetSeconds(Number(text) * 60);
    if (!/^\d{1,3}:\d{2}(?::\d{2})?$/.test(text)) return null;
    const parts = text.split(":").map(Number);
    if (parts.some((part) => !Number.isFinite(part)) || parts.slice(1).some((part) => part >= 60)) return null;
    return normalizeLongVideoOffsetSeconds(parts.length === 3
      ? parts[0] * 3600 + parts[1] * 60 + parts[2]
      : parts[0] * 60 + parts[1]);
  }

  function normalizeLongVideoOffsetSeconds(value) {
    const seconds = Number(value);
    return Number.isFinite(seconds) ? Math.max(0, Math.min(24 * 60 * 60, Math.round(seconds))) : DEFAULT_LONG_VIDEO_EPISODE_OFFSET_SECONDS;
  }

  function formatTimecode(value) {
    const seconds = normalizeLongVideoOffsetSeconds(value);
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const rest = seconds % 60;
    return `${pad2(hours)}:${pad2(minutes)}:${pad2(rest)}`;
  }

  function median(values) {
    const sorted = values.slice().sort((a, b) => a - b);
    const middle = Math.floor(sorted.length / 2);
    return sorted.length % 2 ? sorted[middle] : Math.round((sorted[middle - 1] + sorted[middle]) / 2);
  }

  function captureRouteContext() {
    return {
      href: location.href,
      pageKey: state.pageKey,
      routeSeq: routeRefreshSeq,
    };
  }

  function isRouteContextCurrent(context) {
    return Boolean(context)
      && context.href === location.href
      && context.pageKey === state.pageKey
      && context.routeSeq === routeRefreshSeq;
  }

  function ensureRouteContext(context, message) {
    if (!isRouteContextCurrent(context)) throw new Error(message || "页面已切换，请重新操作。");
  }

  async function mergeBindingKeys(bindingKeys, subjectId) {
    await updateBindings((bindings) => {
      for (const key of bindingKeys) {
        if (!bindings[key]) bindings[key] = subjectId;
      }
    });
  }

  async function updateBindings(update) {
    return withBindingsLock(async () => {
      const latest = await readJsonValueFresh(STORAGE.bindings, {});
      const next = { ...(latest && typeof latest === "object" && !Array.isArray(latest) ? latest : {}) };
      const changed = update(next) !== false;
      if (changed) await writeJsonValueAsync(STORAGE.bindings, next);
      state.bindings = next;
      return next;
    });
  }

  async function updateStoredBindingSubjects(update) {
    return withBindingsLock(async () => {
      const latest = await readJsonValueFresh(STORAGE.bindingSubjects, {});
      const next = { ...(latest && typeof latest === "object" && !Array.isArray(latest) ? latest : {}) };
      const changed = update(next) !== false;
      if (changed) await writeJsonValueAsync(STORAGE.bindingSubjects, next);
      state.bindingSubjects = next;
      return next;
    });
  }

  function withBindingsLock(callback) {
    if (navigator.locks && typeof navigator.locks.request === "function") {
      return navigator.locks.request(BINDINGS_LOCK_NAME, { mode: "exclusive" }, callback);
    }
    const run = bindingsUpdateQueue.catch(() => {}).then(callback);
    bindingsUpdateQueue = run.catch(() => {});
    return run;
  }

  function getActiveEpisodeText() {
    const selectors = [
      ".video-pod__item.active",
      ".video-pod [class*='video-pod__item'][class*='active']",
      ".video-pod [class*='base-item'][class*='active']",
      ".multi-p .page-item.active",
      ".multi-p .page-item.on",
      ".multi-p [class*='page-item'][class*='active']",
      ".multi-p [class*='simple-base-item'][class*='active']",
      ".multi-p [class*='simple-base-item'][class*='on']",
      ".video-episode-card__info-playing",
      ".video-episode-card__info-title--active",
      ".cur-list .on",
      ".episode-list .active",
      ".ep-list .active",
      ".list-box .on",
      "[class*='eplist'][class*='active']",
      "[class*='episode'][class*='active']",
      "[class*='Episode'][class*='active']",
      "[class*='playing']",
    ];
    for (const selector of selectors) {
      const el = document.querySelector(selector);
      const text = getActiveEpisodeNodeText(el);
      if (text) return text;
    }
    const officialProgressNo = getOfficialBangumiProgressEpisodeNo();
    if (officialProgressNo) return `第${officialProgressNo}话`;

    const hiddenPlayerSelectors = [
      ".bpx-player-ctrl-eplist-menu-item.bpx-state-active",
      "[class*='bpx-player-ctrl-eplist-menu-item'][class*='bpx-state-active']",
      "[class*='eplist'][class*='active']",
    ];
    for (const selector of hiddenPlayerSelectors) {
      const el = document.querySelector(selector);
      const text = getActiveEpisodeNodeText(el, false);
      if (text) return text;
    }
    const initial = window.__INITIAL_STATE__ || {};
    const epInfo = initial.epInfo || initial.ep_info || initial.epInfoV2 || {};
    return epInfo.long_title || epInfo.title || epInfo.share_copy || "";
  }

  function getOfficialBangumiProgressEpisodeNo() {
    if (!isOfficialBangumiPage()) return null;
    const selectors = [
      "#eplist_module [class*='eplist_ep_list_progress']",
      "[class*='eplist_ep_list_progress']",
      "#eplist_module [class*='eplist_list_title']",
      "[class*='eplist_list_title']",
    ];
    for (const selector of selectors) {
      const nodes = Array.from(document.querySelectorAll(selector)).filter(isVisible).slice(0, 6);
      for (const node of nodes) {
        const value = parseOfficialBangumiProgressEpisodeNo(node.textContent);
        if (value) return value;
      }
    }
    return null;
  }

  function parseOfficialBangumiProgressEpisodeNo(text) {
    const match = String(text || "").match(/[（(]\s*0*([0-9]{1,3}(?:\.[0-9]+)?)\s*\/\s*0*([0-9]{1,3}(?:\.[0-9]+)?)\s*[）)]/);
    if (!match) return null;
    const current = Number(match[1]);
    const total = Number(match[2]);
    if (!Number.isFinite(current) || !Number.isFinite(total)) return null;
    if (current <= 0 || total <= 0 || current > total) return null;
    return current;
  }

  function getCurrentPartNoFromUrl() {
    try {
      const value = Number(new URL(location.href).searchParams.get("p"));
      return Number.isFinite(value) && value > 0 ? value : null;
    } catch (_) {
      return null;
    }
  }

  function getCurrentVideoPartEpisodeNo() {
    const part = getCurrentVideoPartContext();
    if (part && part.seasonNo) return null;
    if (part && part.partCount > 1) return part.partNo;
    return getCurrentPartNoFromUrl();
  }

  function getActiveEpisodeNodeText(el, requireVisible = true) {
    if (!el || (requireVisible && !isVisible(el))) return "";
    const candidates = [
      el.getAttribute("title"),
      el.getAttribute("aria-label"),
    ];
    const titleSelectors = [
      ".title",
      "[class*='title']",
      "[class*='Title']",
      "[class*='name']",
      "[class*='Name']",
    ];
    for (const selector of titleSelectors) {
      const nodes = Array.from(el.querySelectorAll(selector)).filter((node) => !requireVisible || isVisible(node)).slice(0, 4);
      for (const node of nodes) {
        candidates.push(node.getAttribute("title"), node.getAttribute("aria-label"), node.textContent);
      }
    }
    const rawText = el.textContent || "";
    candidates.push(rawText, stripTrailingDurationText(rawText));
    return candidates
      .map((text) => String(text || "").replace(/\s+/g, " ").trim())
      .find((text) => text && detectEpisodeNo(text)) || "";
  }

  function stripTrailingDurationText(text) {
    return String(text || "")
      .replace(/\s+\d{1,2}:\d{2}(?::\d{2})?\s*$/i, "")
      .replace(/\s+/g, " ")
      .trim();
  }

  function displaySubjectName(subject) {
    return subject.name_cn || subject.name || `subject ${subject.id}`;
  }

  function getCollectionType() {
    return hasCollection() ? Number(state.collection.type) : 3;
  }

  function hasCollection() {
    return Boolean(state.collection && Number(state.collection.type));
  }

  function ensureCollectionForEpisodeSync() {
    if (!hasCollection()) {
      throw new Error("请先在收藏盒选择想看、看过、在看、搁置或抛弃，再同步章节进度。");
    }
  }

  function getCollectionSentence() {
    const label = SUBJECT_TYPES[getCollectionType()] || "在看";
    const verb = label === "看过" ? "看过" : label === "想看" ? "想看" : label === "搁置" ? "搁置" : label === "抛弃" ? "抛弃" : "在看";
    return `我${verb}这部动画`;
  }

  function getRate() {
    return state.collection && Number(state.collection.rate) ? Number(state.collection.rate) : 0;
  }

  function getRateLabel() {
    return getRateLevel(getRate());
  }

  function formatRatePreview(score) {
    const safeScore = Math.max(0, Math.min(10, Number(score) || 0));
    return safeScore ? `${safeScore} ${getRateLevel(safeScore)}` : "未评价";
  }

  function getRateLevel(score, showCaution = true) {
    const labels = {
      1: "不忍直视",
      2: "很差",
      3: "差",
      4: "较差",
      5: "不过不失",
      6: "还行",
      7: "推荐",
      8: "力荐",
      9: "神作",
      10: "超神作",
    };
    const value = Math.max(1, Math.min(10, Math.round(Number(score) || 0)));
    const suffix = showCaution && (value === 1 || value === 10) ? "（请谨慎评价）" : "";
    return labels[value] ? `${labels[value]}${suffix}` : "未评价";
  }

  function getCollectionUpdatedText() {
    const raw = state.collection && state.collection.updated_at;
    if (!raw) return "尚未同步记录时间";
    const date = new Date(raw);
    if (Number.isNaN(date.getTime())) return String(raw);
    return `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()} ${pad2(date.getHours())}:${pad2(date.getMinutes())}`;
  }

  function getNormalEpisodes() {
    return state.episodes
      .filter((ep) => Number(ep.type) === 0)
      .sort((a, b) => Number(a.sort) - Number(b.sort));
  }

  function getEpisodeLocalNo(episode, episodes = getNormalEpisodes()) {
    const index = episodes.findIndex((ep) => Number(ep.id) === Number(episode && episode.id));
    return index >= 0 ? index + 1 : Number(episode && episode.sort) || 0;
  }

  function isCurrentEpisodeNumber(episode, localNo, total) {
    const currentNo = Number(state.currentEpisodeNo);
    if (!Number.isFinite(currentNo) || currentNo <= 0) return false;
    if (currentNo <= Number(total || 0)) return Number(localNo) === currentNo;
    return Number(episode && episode.sort) === currentNo;
  }

  function getEpisodeButtonTitle(episode, localNo) {
    const sort = Number(episode && episode.sort);
    const name = String(episode && (episode.name_cn || episode.name || "") || "").trim();
    const parts = [`第 ${formatEpisodeSort(localNo)} 集`];
    if (Number.isFinite(sort) && sort !== Number(localNo)) parts.push(`Bangumi ep.${formatEpisodeSort(sort)}`);
    if (name) parts.push(name);
    return parts.join(" · ");
  }

  function getEpisodeDiscussionUrl(episodeId) {
    const id = Number(episodeId);
    return Number.isFinite(id) && id > 0 ? `${BGM_WEB_BASE}/ep/${id}` : "";
  }

  function getEpisodeCollectionType(episodeId) {
    const item = state.episodeCollections.find((entry) => entry.episode && Number(entry.episode.id) === Number(episodeId));
    return item ? Number(item.type) : 0;
  }

  function getWatchedCount() {
    return getNormalEpisodes().filter((ep) => getEpisodeCollectionType(ep.id) === 2).length;
  }

  function getProgressInfo() {
    const total = getNormalEpisodes().length;
    const watched = getWatchedCount();
    const percent = total ? Math.min(100, Math.round((watched / total) * 100)) : 0;
    return {
      total,
      watched,
      percent,
      summary: total ? `${watched}/${total} 已看` : "未读取章节",
    };
  }

  function formatEpisodeSort(sort) {
    if (!Number.isFinite(sort)) return "?";
    return sort < 10 ? `0${sort}` : String(sort);
  }

  function formatScore(score) {
    return Number(score) ? Number(score).toFixed(2) : "暂无";
  }

  function formatRank(rank) {
    return Number(rank) ? `#${rank}` : "暂无";
  }

  function formatNumber(value) {
    return Number(value) ? String(value) : "0";
  }

  function pad2(value) {
    return String(value).padStart(2, "0");
  }

  function sleep(ms) {
    return new Promise((resolve) => window.setTimeout(resolve, ms));
  }

  function escapeHtml(value) {
    return String(value == null ? "" : value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }

  function tryParseJson(value) {
    try {
      return value ? JSON.parse(value) : null;
    } catch (_) {
      return null;
    }
  }

  function readValue(key, fallback) {
    try {
      return GM_getValue(key, fallback);
    } catch (error) {
      throw new Error(`扩展存储不可用，请刷新页面后重试：${error && error.message ? error.message : error}`);
    }
  }

  function writeValue(key, value) {
    try {
      GM_setValue(key, value);
    } catch (error) {
      throw new Error(`扩展存储不可用，请刷新页面后重试：${error && error.message ? error.message : error}`);
    }
  }

  function readValueFresh(key, fallback) {
    return GM_getValueFresh(key, fallback);
  }

  async function readJsonValueFresh(key, fallback) {
    const value = await readValueFresh(key, "");
    if (!value) return fallback;
    return tryParseJson(value) || fallback;
  }

  function writeValueAsync(key, value) {
    return GM_setValueAsync(key, value);
  }

  function writeJsonValueAsync(key, value) {
    return writeValueAsync(key, JSON.stringify(value));
  }

  function writeListValueAsync(key, value) {
    return writeValueAsync(key, JSON.stringify(parseList(value.join("\n"))));
  }

  function readJsonValue(key, fallback) {
    const value = readValue(key, "");
    if (!value) return fallback;
    return tryParseJson(value) || fallback;
  }

  function writeJsonValue(key, value) {
    writeValue(key, JSON.stringify(value));
  }

  function readListValue(key, fallback) {
    const value = readValue(key, "");
    if (!value) return fallback;
    const parsed = tryParseJson(value);
    if (Array.isArray(parsed)) return parseList(parsed.join("\n"));
    return parseList(value);
  }

  function writeListValue(key, value) {
    writeValue(key, JSON.stringify(parseList(value.join("\n"))));
  }

  function parseList(value) {
    return String(value || "")
      .split(/[\n,，;；]+/)
      .map(stripWhitelistComment)
      .map(sanitizeWhitelistToken)
      .filter(Boolean)
      .filter((item, index, list) => list.indexOf(item) === index);
  }

  function parseWhitelistInput(value) {
    const labels = {};
    const items = String(value || "")
      .split(/[\n,，;；]+/)
      .map((rawItem) => {
        const raw = String(rawItem || "").trim();
        const item = sanitizeWhitelistToken(stripWhitelistComment(raw));
        const label = getWhitelistComment(raw);
        if (item && label) labels[item] = label;
        return item;
      })
      .filter(Boolean)
      .filter((item, index, list) => list.indexOf(item) === index);
    return { items, labels };
  }

  function stripWhitelistComment(value) {
    return String(value || "").replace(/\s*#.*$/, "").trim();
  }

  function sanitizeWhitelistToken(value) {
    const token = String(value || "").trim();
    if (!token || isSuspiciousWhitelistToken(token)) return "";
    return token;
  }

  function isSuspiciousWhitelistToken(value) {
    const token = String(value || "").trim();
    return token.length > 120
      || /[{};]/.test(token)
      || /\b(?:window|document|function|var|let|const|performance|playerInfo|embedPlayer)\b/i.test(token);
  }

  function normalizeStoredWhitelist() {
    const rawWhitelist = readValue(STORAGE.whitelist, "");
    const parsedRaw = tryParseJson(rawWhitelist);
    const rawWhitelistText = Array.isArray(parsedRaw) ? parsedRaw.join("\n") : rawWhitelist;
    const migrated = parseWhitelistInput(rawWhitelistText);
    const cleanedWhitelist = parseList([...state.whitelist, ...migrated.items].join("\n"));
    const changedWhitelist = cleanedWhitelist.join("\n") !== state.whitelist.join("\n");
    state.whitelist = cleanedWhitelist;
    state.whitelistLabels = pruneWhitelistLabels({ ...state.whitelistLabels, ...migrated.labels }, state.whitelist);
    if (changedWhitelist || Object.keys(migrated.labels).length) writeListValue(STORAGE.whitelist, state.whitelist);
    writeJsonValue(STORAGE.whitelistLabels, state.whitelistLabels);
  }

  function getWhitelistComment(value) {
    const match = String(value || "").match(/#\s*(.+)$/);
    return match ? cleanOwnerName(match[1]) : "";
  }

  function parseTags(value) {
    return String(value || "")
      .split(/[\s,，;；]+/)
      .map((item) => item.trim())
      .filter(Boolean)
      .filter((item, index, list) => list.indexOf(item) === index)
      .slice(0, 10);
  }

  function bindExtensionBridge() {
    if (!isExtensionRuntimeAvailable() || window.__biligumiConnectorExtensionBridgeBound) return;
    window.__biligumiConnectorExtensionBridgeBound = true;

    chrome.runtime.onMessage.addListener((message, _sender, sendResponse) => {
      if (!message || message.type !== "biligumi-oped-execute-skip") return false;
      try {
        sendResponse(executeExtensionOpedSkipCommand());
      } catch (error) {
        sendResponse({ ok: false, reason: "error", error: String(error && error.message || error) });
      }
      return false;
    });

    const notify = (reason, pip) => notifyExtensionPageState(reason, pip == null ? Boolean(document.pictureInPictureElement) : Boolean(pip));
    window.addEventListener("focus", () => notify("focus"), true);
    document.addEventListener("visibilitychange", () => notify(document.visibilityState === "visible" ? "visibility-visible" : "visibility-hidden"), true);
    document.addEventListener("pointerdown", () => notify("pointerdown"), true);
    document.addEventListener("keydown", () => notify("keydown"), true);
    document.addEventListener("enterpictureinpicture", () => notify("enterpictureinpicture", true), true);
    document.addEventListener("leavepictureinpicture", () => notify("leavepictureinpicture", false), true);

    const bindVideoPipEvents = () => {
      document.querySelectorAll("video").forEach((video) => {
        if (video.__biligumiConnectorPipTracked) return;
        video.__biligumiConnectorPipTracked = true;
        video.addEventListener("enterpictureinpicture", () => notify("enterpictureinpicture", true), true);
        video.addEventListener("leavepictureinpicture", () => notify("leavepictureinpicture", false), true);
      });
    };
    bindVideoPipEvents();
    new MutationObserver(bindVideoPipEvents).observe(document.documentElement, { childList: true, subtree: true });
    notify("bridge-bound");
  }

  function executeExtensionOpedSkipCommand() {
    if (!shouldShowOpedSkipButton()) return { ok: false, handled: true, reason: "not-bound-or-disabled" };
    const config = getOpedSkipConfig();
    if (!config.enabled) return { ok: false, reason: "disabled" };
    const video = getActiveVideoElement();
    if (!video) return { ok: false, reason: "no-video" };
    const from = Number(video.currentTime) || 0;
    const duration = Number(video.duration);
    skipOpedForActiveVideo();
    const to = Number(video.currentTime) || from;
    notifyExtensionPageState("skip-command", Boolean(document.pictureInPictureElement));
    return {
      ok: to !== from || config.seconds === 0,
      reason: to !== from ? "skipped" : "unchanged",
      seconds: config.seconds,
      from,
      to,
      duration: Number.isFinite(duration) ? duration : null,
      title: document.title,
      url: location.href,
    };
  }

  function notifyExtensionPageState(reason, pip) {
    if (!isExtensionRuntimeAvailable()) return;
    try {
      chrome.runtime.sendMessage({
        type: "biligumi-oped-page-state",
        reason,
        pip: Boolean(pip),
        url: location.href,
        title: document.title,
        visibilityState: document.visibilityState,
        hasVideo: Boolean(getActiveVideoElement()),
      }, () => {
        void chrome.runtime.lastError;
      });
    } catch (_) {
      // Extension context can disappear during reloads or updates.
    }
  }

  function isExtensionRuntimeAvailable() {
    return typeof chrome !== "undefined" && chrome.runtime && chrome.runtime.id;
  }

